VALUES
  ('retired-d0d1b9a2-moex-00450', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關專責道路興建工程，其預算係按建設計畫分別編列。於X0年1月1日即自行辦理道路拓 寬，共投入人事費3億元、興建道路所需砂石等原料40億元、徵收土地20億元、新購用施工機 具10億元及其他工程相關支出27億元。前述新購置的施工機具，俟工程完工驗收後，將由某機 關統籌管理，供機關其他興建或維護工程使用，該等機具的耐用年限5年。工程於X3年11月10 日竣工，於X4年4月1日驗收完成並通車。下列關於甲機關之會計處理，何者錯誤？', '["人事費、砂石等原料及其他工程相關支出，均為土地改良物的取得成本", "除土地外，其他包括人事費、砂石原料及其他工程相關支出等全部支出，施工期間均以在建工 程入帳", "在X4年4月1日以前施工機具的折舊費用，應資本化為土地改良物成本", "除土地外，其他包括人事費、砂石原料、購置新施工機具及其他工程相關支出等全部支出，均 為土地改良物成本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00451', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關於X1年12月5日與學術機構簽訂委辦契約辦理人口結構大數據分析模型計畫，並依契約 規定預先撥付資料蒐集費100萬元；簽約後甲機關發現該計畫與某公務機關計畫相似，於X2年 3月1日與學術機構協議解約不再執行，並將經費賸餘改列應收款項，學術機構並同意繳回80萬 元，試依中央政府普通公務單位會計制度之一致規定，甲機關於收回之繳庫款項時應為之會計分 錄？', '["借：繳付公庫數 800,000元，貸：其他應收款800,000元", "借：繳付公庫數 800,000元，貸：預付款800,000元", "借：公庫撥入數 800,000元，貸：其他應收款800,000元", "借：公庫撥入數 800,000元，貸：預付款800,000元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00452', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關X8年度以融資租賃方式向A廠商租用影印機一台，租期6年，每年年底給付租金$38,000， X8年度應攤銷之融資租賃負債為$37,000，X8年度應提列之折舊費用為$2,000，依中央政府普通 公務單位會計制度之一致規定，上開交易將使甲機關 X8 年度經費累計表之累計實現數淨增加多 少？', '["$37,000", "$38,000", "$39,000", "$40,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00453', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '承上題，甲機關X8年度收入支出表之收支餘絀淨變動數為何？', '["$38,000", "$36,000", "$35,000", "$3,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00454', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依國有財產會計制度之規定，房屋財產增加3億元時，應做何種會計分錄？', '["借：房屋建築3億元，貸：國有財產總額3億元", "借：房屋建築3億元，貸：資本資產總額3億元", "借：房屋建築及設備3億元，貸：國有財產總額3億元", "借：房屋建築及設備3億元，貸：資本資產總額3億元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00455', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '甲機關之公務車輛執行公務時，不慎與A車發生碰撞，經雙方同意依交通裁決所判定，由甲機關 負60%肇事責任，A車主負40%肇事責任。經保養廠估價，A車維修費用為$80,000，另保險公司 將理賠甲機關$24,000，依中央政府普通公務單位會計制度之一致規定，甲機關應為之分錄為何？', '["借：其他獎補捐助$80,000，貸：負債準備$80,000 借：其他應收款 $24,000，貸：獎補助支出 $24,000", "借：其他獎補捐助$80,000，貸：負債準備$80,000 借：其他應收款$24,000，貸：其他收入$24,000", "借：其他獎補捐助$48,000，貸：負債準備$48,000 借：其他應收款$24,000，貸：罰款及賠償收 入 $24,000", "借：其他獎補捐助 $48,000，貸：其他應付款$48,000 借：其他應收款 24,000，貸：其他收入 24,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00456', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依政府會計準則公報之規定，下列何者為政府年度會計報告之必要補充資訊應敘明事項？', '["依法應編預算送立法院之行政法人資產、負債等資訊", "重要施政計畫執行成果之說明", "財務報表之報導範圍", "公務機關與特種基金間內部往來沖銷之資訊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00457', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央總會計制度規定，下列何種報表為營業基金應編製之財務報表？①平衡表  ②損益表', '["現金流量表", "餘絀撥補表", "僅", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00458', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '中央政府某公務機關於X1年1月1日奉機關首長核准設立30,000元零用金，並撥用相關款項備 作零星之用，業務執行過程陸續以零用金支付加班費等人事支出12,000元，差旅費6,000元，講 師鐘點費 8,000 元，出納管理人員發現零用金額度明顯不足，經機關首長核准同意增撥零用金 20,000元，試依中央政府普通公務單位會計制度之一致規定，於增撥時應為之會計分錄？', '["借：零用金26,000元，貸：公庫撥入數26,000元", "借：零用金20,000元，貸：公庫撥入數20,000元", "借：支出26,000元，貸：公庫撥入數26,000元", "借：支出20,000元，貸：公庫撥入數20,000元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00459', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-ac2adf20', 'sub-retired-d0d1b9a2-03', NULL, 'single_choice', '依中央公共債務會計制度之規定，經理機構定期對外之會計報告，至少應包括下列何者？', '["日報、旬報、會計月報及半年度會計報告", "會計月報、會計季報及年度會計報告", "日報、會計月報及年度會計報告", "日報、旬報、會計季報及年度會計報告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:14+00:00", "source_pdf_sha1": "2339d4d8c815", "answer_pdf_sha1": "d6eff6cbd3aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
